   tsx
// CreateUserForm.tsx
import { useCreateUser } from '@/api/generated/users'

export function CreateUserForm   {
  const { mutate: createUser, isPending } = useCreateUser {
    onSuccess:  newUser  =  {
      console.log '생성 완료:', newUser.id 
    },
  } 

  const handleSubmit =  e: React.FormEvent<HTMLFormElement   =  {
    e.preventDefault  
    const form = new FormData e.currentTarget 
    createUser {
      name: form.get 'name'  as string,
      email: form.get 'email'  as string,
    } 
  }

  return  
    <form onSubmit={handleSubmit} 
      <input name="name" placeholder="이름" / 
      <input name="email" placeholder="이메일" / 
      <button type="submit" disabled={isPending} 
        {isPending ? '생성 중...' : '생성'}
      </button 
    </form 

}


타입, 함수, 훅 모두 자동 생성된 것을 그대로 사용한다. 백엔드 스펙이 바뀌면  npx orval 을 다시 실행하면 TypeScript 컴파일러가 타입 불일치를 즉시 알려준다.

---

   MSW mock 자동 생성

 @mswjs/msw  와 함께 사용하면 API 모킹 핸들러도 자동 생성된다. 백엔드 없이 프론트엔드 개발을 진행할 때 유용하다.

   typescript
// orval.config.ts — mock 추가
export default defineConfig {
  petstore: {
    input: { target: './openapi.yaml' },
    output: {
      target: './src/api/generated',
      client: 'react-query',
    },
  },
  petstoreMock: {
    input: { target: './openapi.yaml' },
    output: {
      target: './src/api/mocks',
      client: 'msw',                  // MSW 핸들러 생성
    },
  },
} 


   typescript
// 자동 생성된 MSW 핸들러  개념적 예시 
// src/api/mocks/users.ts
import { http, HttpResponse } from 'msw'

export const usersHandlers =  
  http.get '/users/:id',    =  {
    return HttpResponse.json { id: 1, name: 'Alice', email: 'alice@example.com' } 
  } ,
  http.post '/users',    =  {
    return HttpResponse.json { id: 2, name: 'Bob', email: 'bob@example.com' }, { status: 201 } 
  } ,



---

   package.json 스크립트 등록

   json
{
  "scripts": {
    "api:generate": "orval",
    "api:generate:watch": "orval --watch"
  }
}


 --watch  옵션을 사용하면 OpenAPI 파일이 변경될 때마다 자동으로 재생성한다.

---

   수동 작성 대비 Orval의 이점

| 항목 | 수동 작성 | Orval |
|------|---------|-------|
| 타입 정의 | 매번 직접 작성 | 자동 생성 |
| API 함수 | 매번 직접 작성 | 자동 생성 |
| React Query 훅 | 매번 직접 작성 | 자동 생성 |
| 스펙 변경 반영 | 수동으로 전파 | 재생성 후 컴파일러가 감지 |
| 타입 불일치 | 런타임에 발견 | 빌드 타임에 발견 |

---

Orval의 핵심 가치는   백엔드와 프론트엔드 사이의 계약 OpenAPI 스펙 을 코드로 자동 변환  한다는 것이다. API 클라이언트를 손으로 유지보수하는 시간을 없애고, 타입 안전성을 빌드 타임에 보장한다.

React에서 성능 최적화를 이야기할 때 가장 먼저 나오는 API가  memo ,  useMemo ,  useCallback 이다.
셋 다 "메모이제이션"이라는 이름을 달고 있지만,   무엇을   메모이제이션하는지가 완전히 다르다.

   세 가지 비교 요약

| API | 메모이제이션 대상 | 목적 |
|-----|----------------|------|
|  React.memo  |   컴포넌트   | props가 같으면 리렌더 건너뜀 |
|  useMemo  |   계산 결과값   | 의존성이 같으면 이전 값 재사용 |
|  useCallback  |   함수 참조   | 의존성이 같으면 이전 함수 재사용 |

---

   React.memo — 컴포넌트 리렌더 방지

 React.memo 는   고차 컴포넌트 HOC   다. 컴포넌트를 감싸면, 부모가 리렌더되더라도 props가 변경되지 않았다면 해당 컴포넌트의 리렌더를 건너뛴다.

   tsx
// memo 없이
function Avatar { name, imageUrl }: { name: string; imageUrl: string }  {
  console.log 'Avatar 렌더링' 
  return <img src={imageUrl} alt={name} / 
}

// 부모가 리렌더될 때마다 Avatar도 무조건 리렌더됨


   tsx
// memo 적용
const Avatar = React.memo function Avatar {
  name,
  imageUrl,
}: {
  name: string
  imageUrl: string
}  {
  console.log 'Avatar 렌더링' 
  return <img src={imageUrl} alt={name} / 
} 

// name, imageUrl이 동일하면 부모 리렌더 시에도 Avatar는 건너뜀


    비교 방식: 얕은 비교 Shallow Equality 

기본적으로 각 prop을  Object.is 로 비교한다. 객체/배열/함수는 참조가 다르면 다른 값으로 판단한다.

   tsx
function Parent   {
  const  count, setCount  = useState 0 

  // ❌ 렌더링마다 새 객체/함수 생성 → Avatar는 매번 리렌더
  const style = { color: 'red' }
  const handleClick =    =  console.log 'clicked' 

  return  
    < 
      <button onClick={   =  setCount c =  c + 1 } +</button 
      <Avatar name="Alice" style={style} onClick={handleClick} / 
    </ 

}


    커스텀 비교 함수

두 번째 인수로 비교 함수를 넘기면 더 세밀하게 제어할 수 있다.

   tsx
const Avatar = React.memo 
  function Avatar { user }: { user: User }  {
    return <img src={user.imageUrl} alt={user.name} / 
  },
   prevProps, nextProps  =  {
    // true 반환 → 리렌더 건너뜀
    // false 반환 → 리렌더 수행
    return prevProps.user.id === nextProps.user.id
  }



---

   useMemo — 계산 결과값 캐싱

 useMemo 는   비용이 큰 계산 결과를 캐싱  한다. 의존성 배열의 값이 변경될 때만 재계산한다.

   tsx
function ProductList { products, filter }: Props  {
  // ❌ 매 렌더링마다 전체 필터링 수행
  const filtered = products.filter p =  p.category === filter 

  // ✅ filter나 products가 바뀔 때만 재계산
  const filtered = useMemo 
       =  products.filter p =  p.category === filter ,
     products, filter 


  return <ul {filtered.map p =  <li key={p.id} {p.name}</li  }</ul 
}


    참조 안정화에도 사용

계산이 가볍더라도   객체/배열의 참조를 안정시켜 memo 컴포넌트의 리렌더를 막을 때   사용한다.

   tsx
function Parent { userId }: { userId: string }  {
  // ❌ 렌더링마다 새 객체 → 자식의 memo 무력화
  const config = { userId, theme: 'dark' }

  // ✅ userId가 바뀔 때만 새 객체 생성
  const config = useMemo    =   { userId, theme: 'dark' } ,  userId  

  return <MemoChild config={config} / 
}


---

   useCallback — 함수 참조 안정화

 useCallback 은   함수 자체를 캐싱  한다. 의존성이 바뀌지 않으면 같은 함수 참조를 반환한다.

   tsx
// useCallback fn, deps  === useMemo    =  fn, deps 
// 둘은 사실상 같다. useCallback은 함수에 특화된 문법적 편의 버전이다.


   tsx
function TodoList { todos }: { todos: Todo   }  {
  const  text, setText  = useState '' 

  // ❌ 렌더링마다 새 함수 생성 → MemoTodoItem의 memo 무력화
  const handleDelete =  id: string  =  {
    deleteTodo id 
  }

  // ✅ 참조 안정화
  const handleDelete = useCallback  id: string  =  {
    deleteTodo id 
  },      // deleteTodo가 안정적이면 빈 배열

  return  
    < 
      <input value={text} onChange={e =  setText e.target.value } / 
      {todos.map todo =   
        <MemoTodoItem key={todo.id} todo={todo} onDelete={handleDelete} / 
        }
    </ 

}


    이벤트 핸들러에서의 useCallback

단순 이벤트 핸들러에는  useCallback 이   불필요  한 경우가 많다.

   tsx
// ❌ 과도한 useCallback — 의미 없음
// 이 컴포넌트가 memo로 감싸지지 않았다면 useCallback은 오히려 비용만 추가
function SimpleButton   {
  const handleClick = useCallback    =  {
    console.log 'clicked' 
  },    

  return <button onClick={handleClick} 클릭</button 
}

// ✅ memo 자식에게 전달하거나, 의존성으로 사용될 때만 useCallback


---

   세 가지를 조합하는 전형적인 패턴

   tsx
// 부모 컴포넌트
function Dashboard { userId }: { userId: string }  {
  const  filter, setFilter  = useState 'all' 

  // 1. 비용이 큰 데이터 가공 → useMemo
  const chartData = useMemo    =  buildChartData userId, filter ,  userId, filter  

  // 2. 자식에게 넘길 함수 → useCallback
  const handleFilterChange = useCallback  next: string  =  {
    setFilter next 
  },    

  return  
    < 
      {/  3. 자주 리렌더되지 않아야 할 컴포넌트 → memo  /}
      <MemoFilterBar current={filter} onChange={handleFilterChange} / 
      <MemoChart data={chartData} / 
    </ 

}

const MemoFilterBar = React.memo FilterBar 
const MemoChart = React.memo Chart 


---

   남용했을 때의 부작용

메모이제이션은   공짜가 아니다.   이전 값 저장, 의존성 비교, 클로저 유지에 메모리와 CPU가 소비된다.


useMemo / useCallback 비용:
  - 의존성 배열 각 항목을 Object.is로 비교
  - 이전 값을 Fiber 노드의 memoizedState에 보관
  - 클로저가 외부 변수를 계속 참조

불필요한 경우:
  - 계산이 매우 단순한 경우  덧셈, 문자열 연결 등 
  - 자식 컴포넌트가 memo로 감싸지지 않은 경우
  - 의존성이 매 렌더링마다 바뀌는 경우


   tsx
// ❌ 아무 의미 없는 useMemo
const doubled = useMemo    =  count   2,  count  
// ✅ 그냥 인라인으로
const doubled = count   2

// ❌ 아무 의미 없는 useCallback  자식이 memo가 아님 
const handleChange = useCallback  e  =  setValue e.target.value ,    
// ✅ 그냥 인라인으로
const handleChange =  e  =  setValue e.target.value 


---

   사용 시점 판단 기준


React.memo
  → 부모가 자주 리렌더되고, 해당 컴포넌트의 렌더링 비용이 클 때
  → props가 원시값 위주이거나, 참조를 안정화했을 때

useMemo
  → 계산이 O n  이상이고, 렌더링마다 실행되는 게 눈에 띄게 느릴 때
  → memo 자식에게 객체/배열을 props로 전달할 때 참조 안정화 목적

useCallback
  → memo 자식에게 함수를 props로 전달할 때
  → useEffect / useMemo의 의존성 배열에 함수를 포함해야 할 때


---

   React Compiler  React 19+ 

React 19에서 도입된   React Compiler  는 빌드 타임에 자동으로 메모이제이션을 삽입한다.
올바르게 작성된 컴포넌트라면  memo ,  useMemo ,  useCallback 을 수동으로 쓸 필요가 크게 줄어든다.

   tsx
// React Compiler 적용 시 — 아래 두 코드는 동일하게 최적화됨

// 최적화 전
function Component { items, filter }  {
  const filtered = items.filter i =  i.type === filter 
  return <List items={filtered} / 
}

// 컴파일러가 자동으로 아래처럼 변환
function Component { items, filter }  {
  const filtered = useMemo    =  items.filter i =  i.type === filter ,  items, filter  
  return <MemoList items={filtered} / 
}


단, 사이드 이펙트가 있거나 불변성을 위반하는 코드는 컴파일러가 최적화하지 못하므로, 올바른 React 코드 작성이 선행 조건이다.

---

메모이제이션의 핵심은   "이 컴포넌트/값이 실제로 불필요하게 재계산되고 있는가"를 먼저 측정하고, 그때 적용하는 것  이다.
프로파일링 없이 습관적으로 붙이는  useMemo 와  useCallback 은 코드 복잡도만 높이고 성능 이득은 없는 경우가 많다.

setState 를 분명히 호출했는데 화면이 그대로인 경험은 React를 쓰다 보면 누구나 한 번씩 마주친다.
원인은 거의 항상 하나로 귀결된다 —   React는 이전 상태와 새 상태를  Object.is 로 비교하고, 같으면 리렌더를 건너뛴다.  

   React의 상태 비교 기준: Object.is

   ts
// React 내부  단순화 
function dispatchSetState fiber, queue, action  {
  const newState = typeof action === 'function'
    ? action currentState 
    : action

  // 같으면 리렌더 스킵
  if  Object.is newState, currentState   {
    return
  }

  scheduleUpdateOnFiber fiber 
}


 Object.is 는 원시값은 값 비교, 객체/배열은   참조 레퍼런스  비교  를 한다.

   ts
Object.is 1, 1          // true  → 리렌더 안 함
Object.is 'a', 'a'      // true  → 리렌더 안 함
Object.is {}, {}        // false → 리렌더 함  참조가 다름 
Object.is arr, arr      // true  → 리렌더 안 함  같은 참조 


---

   패턴 1: 객체를 직접 수정 후 setState

가장 흔한 실수다. 기존 객체를 수정한 뒤 같은 참조를 setState에 넘기면 React는 변화를 감지하지 못한다.

   tsx
const  user, setUser  = useState { name: 'Alice', age: 20 } 

// ❌ 기존 객체를 직접 수정
function handleClick   {
  user.age = 21          // user 객체 자체를 변경
  setUser user           // 참조가 그대로 → Object.is user, user  === true → 리렌더 안 함
}

// ✅ 새 객체를 만들어서 넘기기
function handleClick   {
  setUser { ...user, age: 21 }   // 새 참조 → 리렌더 발생
}


---

   패턴 2: 배열을 직접 수정  push, splice, sort… 

   tsx
const  items, setItems  = useState<string       

// ❌ 배열을 직접 변이
function addItem item: string  {
  items.push item        // 배열 내용은 바뀌지만 참조는 그대로
  setItems items         // 리렌더 안 함
}

// ✅ 새 배열 반환
function addItem item: string  {
  setItems  ...items, item           // 추가
}

function removeItem index: number  {
  setItems items.filter   , i  =  i !== index    // 삭제
}

function updateItem index: number, next: string  {
  setItems items.map  v, i  =  i === index ? next : v    // 수정
}


 push ,  pop ,  splice ,  sort ,  reverse  등은 모두 원본 배열을 변이시키므로 사용 금지다.

---

   패턴 3: 중첩 객체를 얕게 복사

스프레드 연산자는   1단계만   복사한다. 중첩된 객체는 여전히 같은 참조를 공유한다.

   tsx
const  state, setState  = useState {
  user: { name: 'Alice', address: { city: 'Seoul' } }
} 

// ❌ 얕은 복사 — state.user.address는 여전히 같은 참조
function handleClick   {
  setState {
    ...state,
    user: {
      ...state.user,
      address: state.user.address,  // 이 부분을 바꾸지 않으면
    }
  } 
  // React 입장: 새 state 객체지만 address가 같으면 하위 컴포넌트 리렌더 안 할 수도 있음
}

// ✅ 변경되는 중첩 수준까지 전부 새 객체로
function updateCity city: string  {
  setState {
    ...state,
    user: {
      ...state.user,
      address: { ...state.user.address, city },
    }
  } 
}


중첩이 깊다면  Immer  https://immerjs.github.io/immer/ 를 쓰면 훨씬 간결해진다.

   tsx
import { produce } from 'immer'

function updateCity city: string  {
  setState produce draft =  {
    draft.user.address.city = city  // 직접 수정처럼 보이지만 내부적으로 새 객체 생성
  }  
}


---

   패턴 4: 같은 원시값으로 setState

값이 실제로 바뀌지 않았다면 리렌더가 일어나지 않는 게 정상이다.
하지만 이걸 모르면 버그라고 착각하기도 한다.

   tsx
const  count, setCount  = useState 0 

// count가 이미 0일 때
setCount 0   // Object.is 0, 0  === true → 리렌더 안 함  의도된 동작 


---

   패턴 5: 클로저가 캡처한 오래된 상태

 useEffect , 이벤트 핸들러 안의 상태 참조가 오래된 클로저를 보고 있을 때 발생한다.
리렌더가 안 되는 것처럼 보이지만 실제로는 이전 상태 기준으로 연산이 잘못된 경우다.

   tsx
const  count, setCount  = useState 0 

// ❌ 클로저가 count=0을 캡처한 채로 고정
useEffect    =  {
  const id = setInterval    =  {
    setCount count + 1   // 항상 0 + 1 = 1이 됨
  }, 1000 
  return    =  clearInterval id 
},      // 의존성 배열이 비어 있어 count가 갱신돼도 콜백은 최초 count=0을 봄

// ✅ 함수형 업데이트로 최신 상태 참조
useEffect    =  {
  const id = setInterval    =  {
    setCount prev =  prev + 1   // 항상 최신 상태 기준 +1
  }, 1000 
  return    =  clearInterval id 
},    


---

   패턴 6: 부모가 리렌더되지 않아 자식도 안 됨

자식 컴포넌트 자체의 상태 변경이 아니라,   props를 통해 받는 값이 바뀌어야 하는데   부모 상태가 업데이트되지 않은 경우다.

   tsx
// ❌ 부모 컴포넌트 — items를 외부 변수로 관리
let items =  'a', 'b'   // React 상태가 아님

function Parent   {
  const handleAdd =    =  {
    items.push 'c'   // React가 모르는 변경 → 부모 리렌더 없음 → 자식도 그대로
  }

  return <Child items={items} / 
}

// ✅ useState로 관리해야 React가 변경을 인식
function Parent   {
  const  items, setItems  = useState  'a', 'b'  

  const handleAdd =    =  {
    setItems  ...items, 'c'  
  }

  return <Child items={items} / 
}


---

   패턴 7: React.memo가 변경을 막는 경우

 React.memo 는 props가 같으면 리렌더를 건너뛴다.
객체/함수 props를 매 렌더링마다 새로 생성하면  memo 가 항상 새 참조를 받아 리렌더가 일어나고,
반대로  useMemo / useCallback  없이 복잡한 비교를 기대하면 원하는 시점에 리렌더가 안 될 수 있다.

   tsx
// ❌ 매 렌더링마다 새 객체 생성 → memo 무력화
function Parent   {
  return <MemoChild config={{ theme: 'dark' }} /   // 매번 새 참조
}

// ✅ useMemo로 참조 안정화
function Parent   {
  const config = useMemo    =   { theme: 'dark' } ,    
  return <MemoChild config={config} / 
}


---

   진단 체크리스트


리렌더가 안 일어난다면 순서대로 확인

1. setState에 넘기는 값이 새 참조인가?
   → 객체/배열이면 스프레드/map/filter로 새 참조 생성

2. 중첩 객체라면 변경된 수준까지 전부 새 객체로 만들었는가?

3. 배열을 push/splice/sort로 직접 변이하지 않았는가?

4. 함수형 업데이트 prev =  ... 를 써야 하는 상황인가?
   → 이전 상태를 기반으로 새 상태를 계산할 때는 항상 함수형 업데이트

5. React.memo가 변경을 가로막고 있지 않은가?

6. 변경되는 값이 React 상태인가, 일반 변수인가?


---

React가 리렌더를 건너뛰는 것은 버그가 아니라   의도된 최적화  다.
"상태가 바뀌었다"는 것을 React에게 알리려면 반드시 새로운 참조나 새로운 원시값을 setState에 넘겨야 한다.
불변성 Immutability 은 React와의 계약이다.

React 컴포넌트를 작성하다 보면 예상치 못한  0 이 화면에 나타나거나, 아무것도 없어야 할 자리에 텍스트가 보이는 경험을 한다. 대부분 falsy 값을  && 로 조건부 렌더링할 때 생기는 문제다. JavaScript의 falsy 동작 방식과 JSX의 렌더링 규칙이 미묘하게 다르기 때문이다.

   JSX에서 렌더링되는 값과 되지 않는 값

React가 JSX를 처리할 때, 모든 falsy 값이 동일하게 무시되지 않는다.

| 값 | 렌더링 결과 |
|----|------------|
|  false  | 아무것도 렌더링하지 않음 |
|  null  | 아무것도 렌더링하지 않음 |
|  undefined  | 아무것도 렌더링하지 않음 |
|  ''   빈 문자열  | 아무것도 렌더링하지 않음 |
|  0  |    0 을 렌더링함   |
|  NaN  |    NaN 을 렌더링함   |

 0 과  NaN 은 JavaScript에서 falsy지만, React는 이것들을 텍스트 노드로 렌더링한다.

---

   대표적인 실수: && 연산자

   tsx
function Cart { items }: { items: string   }  {
  return  
    <div 
      {items.length && <ItemList items={items} / }
    </div 

}


 items 가 비어 있으면  items.length 는  0 이다.  0 && <ItemList /  는  0 을 반환한다. 결과적으로 화면에  0 이 렌더링된다.


items =     →  0 && <ItemList /   →  0  →  화면에 "0" 출력


    올바른 패턴

  Boolean 변환:  

   tsx
{items.length   0 && <ItemList items={items} / }
{!!items.length && <ItemList items={items} / }
{Boolean items.length  && <ItemList items={items} / }


  삼항 연산자:  

   tsx
{items.length   0 ? <ItemList items={items} /  : null}


 items.length   0 이  false 일 때  null 을 반환하므로 아무것도 렌더링되지 않는다.

---

   숫자 0이 실수가 되는 다른 패턴들

   tsx
// count가 0이면 화면에 "0" 출력
{count && <Badge count={count} / }

// price가 0이면 화면에 "0" 출력
{price && <span ₩{price}</span }

// index가 0이면 화면에 "0" 출력
{index && <Divider / }


숫자를 조건으로 쓸 때는 항상 비교 연산자를 사용한다.

   tsx
{count   0 && <Badge count={count} / }
{price !== 0 && <span ₩{price}</span }
{index !== 0 && <Divider / }


---

   TypeScript가 잡아주는 경우

TypeScript는 일부 상황에서 이 실수를 컴파일 타임에 감지한다.

   tsx
function Component { value }: { value: number }  {
  // TS 에러: 'number' type은 JSX children으로 사용 불가  tsconfig에 따라 다름 
  // 실제로는 에러가 안 날 수 있음
  return <div {value && <span 있음</span }</div 
}


그러나 TypeScript가 항상 잡아주지는 않는다.  value 가  number | undefined  타입이면  && 를 쓰더라도 에러가 발생하지 않는다.

   tsx
function Component { count }: { count: number | undefined }  {
  // TypeScript 에러 없음 — 하지만 count가 0이면 화면에 "0" 출력
  return <div {count && <Badge / }</div 
}


TypeScript의 타입 시스템은 "이 값이 JSX에서 어떻게 렌더링될지"를 검사하지 않는다. 타입이 맞으면 통과된다.

    ESLint로 감지

 eslint-plugin-react 의  react/jsx-no-leaked-render  룰이 이 패턴을 잡아준다.

   json
{
  "rules": {
    "react/jsx-no-leaked-render":  "error", { "validStrategies":  "ternary", "coerce"  } 
  }
}


   tsx
// ESLint 에러
{count && <Badge / }

// OK
{count   0 && <Badge / }
{!!count && <Badge / }


---

   null vs undefined 렌더링

   tsx
function Component { label }: { label: string | null | undefined }  {
  return <div {label}</div 
}


-  label = null  → 아무것도 렌더링하지 않음
-  label = undefined  → 아무것도 렌더링하지 않음
-  label = ''  → 빈 문자열, 아무것도 보이지 않음  하지만 DOM에 빈 텍스트 노드 존재 

세 가지 모두 화면에 보이지 않지만,  null / undefined 와  '' 는 목적이 다르다.  null / undefined 는 "데이터 없음"이고,  '' 는 "빈 문자열"이다. 명시적으로 구분하는 것이 타입 안전성에 좋다.

---

   옵셔널 prop과 기본값

   tsx
interface Props {
  title?: string       // string | undefined
  count?: number       // number | undefined
  isActive?: boolean   // boolean | undefined
}

function Card { title, count, isActive }: Props  {
  return  
    <div 
      {/  title이 undefined면 아무것도 렌더링 안 함 — 안전  /}
      {title && <h2 {title}</h2 }

      {/  count가 0이면 "0" 렌더링 — 위험  /}
      {count && <span {count}개</span }

      {/  isActive가 undefined이면 렌더링 안 함 — 안전하지만 의도 불명확  /}
      {isActive && <ActiveBadge / }
    </div 

}


기본값으로 명확히 하는 것이 낫다.

   tsx
function Card { title, count = 0, isActive = false }: Props  {
  return  
    <div 
      {title && <h2 {title}</h2 }
      {count   0 && <span {count}개</span }
      {isActive && <ActiveBadge / }
    </div 

}


---

   빈 문자열 조건부 렌더링

   tsx
function Label { text }: { text: string }  {
  // text가 빈 문자열일 때 아무것도 렌더링 안 함 — 의도적?
  return <div {text && <span className="label" {text}</span }</div 
}


빈 문자열도  && 에서 falsy로 처리된다.  text 가  '' 이면  <span  이 렌더링되지 않는다. 빈 문자열을 명시적으로 제외하려는 의도라면 괜찮지만, 의도가 불분명하면 명시적으로 쓰는 것이 낫다.

   tsx
{text.length   0 && <span className="label" {text}</span }
{text !== '' && <span className="label" {text}</span }


---

   실전 정리

   tsx
// ❌ 숫자를 && 조건으로 바로 사용
{items.length && <List / }
{count && <Badge / }

// ✅ 비교 연산으로 Boolean 확보
{items.length   0 && <List / }
{count   0 && <Badge / }

// ✅ 또는 삼항 연산자
{items.length   0 ? <List /  : null}

// ✅ Boolean 변환  간결하게 
{!!items.length && <List / }

// ❌ 문자열도 체크 필요한 경우
{text && <Label text={text} / }

// ✅ 명시적 확인
{text !== '' && <Label text={text} / }


TypeScript를 쓴다고 falsy 렌더링 버그가 사라지지 않는다. 타입 시스템과 JSX 렌더링 규칙은 별개의 레이어다.  &&  왼쪽에 숫자가 오는 순간 항상 의심하고, 비교 연산자로 명시적으로 Boolean을 만드는 습관이 가장 확실한 방어책이다.

useEffect 를 작성하다 보면 의존성 배열 때문에 난처한 상황이 생긴다. Effect가 어떤 값을 읽어야 하는데, 그 값이 바뀔 때마다 Effect를 재실행하고 싶지는 않은 경우다.  useEffectEvent 는 이 문제를 해결하기 위해 제안된 실험적 훅이다.

    참고:    useEffectEvent 는 React 18.3 기준 실험적 API다.  experimental  채널에서만 사용 가능하며, 안정 API가 되는 시점에 이름이나 동작이 바뀔 수 있다.

   문제: Effect 의존성의 딜레마

채팅방에 연결하면서 연결 시 로그를 남기는 코드를 보자.

   tsx
function ChatRoom { roomId }  {
  const  messages, setMessages  = useState    

  useEffect    =  {
    const connection = createConnection roomId 
    connection.connect  
    connection.on 'message',  msg  =  {
      setMessages prev =   ...prev, msg  
    } 
    return    =  connection.disconnect  
  },  roomId  
  // ...
}


여기에 로그 기능을 추가한다. 로그 레벨은 설정에서 읽어온다.

   tsx
function ChatRoom { roomId }  {
  const  messages, setMessages  = useState    
  const logLevel = useLogLevel    // 외부 상태

  useEffect    =  {
    const connection = createConnection roomId 
    connection.on 'connect',    =  {
      logConnection roomId, logLevel   // logLevel 사용
    } 
    connection.connect  
    return    =  connection.disconnect  
  },  roomId, logLevel    // logLevel을 의존성에 추가해야 함


문제가 생겼다.  logLevel 이 의존성에 포함되었기 때문에,   사용자가 로그 레벨을 바꿀 때마다 채팅방 연결이 끊어지고 다시 연결된다.   이것은 원하는 동작이 아니다.

 logLevel 은 연결이 설정될 때 읽기만 하면 되고,  logLevel 이 바뀐다고 채팅방을 재연결할 이유가 없다.

   잘못된 해결책들

    의존성 배열에서 제거  lint 무시 

   tsx
useEffect    =  {
  const connection = createConnection roomId 
  connection.on 'connect',    =  {
    logConnection roomId, logLevel 
  } 
  connection.connect  
  return    =  connection.disconnect  
// eslint-disable-next-line react-hooks/exhaustive-deps
},  roomId    // logLevel 빠뜨림


이 코드는  logLevel 이 바뀌어도 Effect가 재실행되지 않아서 클로저 안에 오래된  logLevel 이 남는다. 버그다.

    ref로 감싸기

   tsx
const logLevelRef = useRef logLevel 
useEffect    =  { logLevelRef.current = logLevel } 

useEffect    =  {
  const connection = createConnection roomId 
  connection.on 'connect',    =  {
    logConnection roomId, logLevelRef.current   // ref로 접근
  } 
  connection.connect  
  return    =  connection.disconnect  
},  roomId  


동작은 하지만 패턴이 장황하고 의도가 불명확하다.

   useEffectEvent

 useEffectEvent 는 Effect 안에서 쓰는 "이벤트 핸들러"를 만든다. 이 핸들러는:
1. Effect 의존성이 아니다  변경 시 Effect 재실행 없음 
2. 항상 최신 값을 읽는다  오래된 클로저 문제 없음 

   tsx
import { experimental useEffectEvent as useEffectEvent } from 'react'

function ChatRoom { roomId }  {
  const  messages, setMessages  = useState    
  const logLevel = useLogLevel  

  // Effect Event — 의존성이 아니지만 항상 최신 logLevel을 읽음
  const onConnect = useEffectEvent    =  {
    logConnection roomId, logLevel 
  } 

  useEffect    =  {
    const connection = createConnection roomId 
    connection.on 'connect', onConnect   // onConnect는 의존성에 추가 안 함
    connection.connect  
    return    =  connection.disconnect  
  },  roomId    // roomId만 의존성


 onConnect 는  roomId 가 바뀔 때만 Effect가 재실행되도록 하면서, 실행 시점에는 항상 최신  logLevel 을 읽는다.

   핵심 개념: 반응형 vs 비반응형

React의 Effect는   반응형 reactive   이다. 의존성이 바뀌면 재실행된다.

Effect Event는   비반응형 non-reactive   이다. 값이 바뀌어도 재실행을 유발하지 않지만, 호출될 때는 최신 값을 가진다.

   tsx
// 이 구분이 핵심
useEffect    =  {
  // 반응형 코드: roomId가 바뀌면 재실행됨
  const connection = createConnection roomId 

  connection.on 'message', onMessage   // onMessage는 비반응형

  connection.connect  
  return    =  connection.disconnect  
},  roomId    // roomId에만 반응


   더 많은 예시

    방문 로깅

   tsx
function Page { url }  {
  const { userId } = useAuth  

  const onVisit = useEffectEvent  visitedUrl  =  {
    logVisit visitedUrl, userId   // userId는 반응형 아님
  } 

  useEffect    =  {
    onVisit url 
  },  url    // url이 바뀔 때만 실행, userId 변경 시 재실행 없음
}


    장바구니 알림

   tsx
function ProductPage { productId }  {
  const  addedToCart, setAddedToCart  = useState false 
  const { theme } = useTheme  

  const onConnected = useEffectEvent    =  {
    if  addedToCart  {
      showNotification '상품이 이미 장바구니에 있습니다', theme 
    }
  } 

  useEffect    =  {
    const connection = createProductConnection productId 
    connection.on 'connected', onConnected 
    connection.connect  
    return    =  connection.disconnect  
  },  productId  
  // addedToCart, theme이 바뀌어도 재연결 없음
}


   제약사항

 useEffectEvent 에는 중요한 제약이 있다.

  Effect 안에서만 호출해야 한다.  

   tsx
const onConnect = useEffectEvent    =  {
  // ...
} 

// ❌ Effect 밖에서 호출 불가
function handleClick   {
  onConnect    // 잘못된 사용
}

// ✅ Effect 안에서만 사용
useEffect    =  {
  connection.on 'connect', onConnect   // 올바른 사용
  // ...
},    


  Effect Event를 다른 컴포넌트나 훅에 전달하지 않는다.  

   tsx
// ❌
function useTimer callback  {
  useEffect    =  {
    const id = setInterval callback, 1000 
    return    =  clearInterval id 
  },  callback  
}

// ✅ — 내부에서 useEffectEvent 처리
function useTimer callback  {
  const onTick = useEffectEvent callback 
  useEffect    =  {
    const id = setInterval onTick, 1000 
    return    =  clearInterval id 
  },      // callback 변경에 영향받지 않음
}


   Effect Event vs useCallback

언뜻 비슷해 보이지만 목적이 다르다.

   tsx
// useCallback — 함수 참조를 안정화  의존성에 포함됨 
const handleSubmit = useCallback    =  {
  submit formData 
},  formData    // formData 변경 시 새 함수 생성

// useEffectEvent — Effect 안의 비반응형 로직  의존성에 포함 안 됨 
const onSubmit = useEffectEvent    =  {
  logSubmit formData   // 항상 최신 formData 읽음, 하지만 재실행 유발 안 함
} 


---

 useEffectEvent 는 "Effect는  roomId 에 반응해야 하지만, 로그 레벨에는 반응하지 않아야 한다"는 의도를 코드로 명확히 표현할 수 있게 해준다. Effect의 의존성 배열을  eslint-disable 로 속이거나  ref  패턴을 반복하는 것보다 훨씬 의도가 명확하다. 안정 API가 되는 시점을 기다리며 개념을 이해해두면 도움이 된다.

캐시 없이 모든 요청을 DB에서 처리하면 응답 속도는 느려지고, DB 부하는 급격히 증가한다.
Redis를 사용한 캐싱 전략을 올바르게 선택하면 응답 속도와 DB 부하를 동시에 개선할 수 있다.

   캐싱이란 무엇인가

캐시 Cache 는 자주 조회되는 데이터를 빠른 저장소에 임시로 보관하는 기법이다.
Redis는 인메모리 데이터 구조 저장소로, 마이크로초 단위 응답 속도를 제공해 캐시 레이어로 가장 널리 쓰인다.


Client →  Redis Cache  →  캐시 히트 시 즉시 반환 
                       →  캐시 미스 시  → DB → Redis 저장 → 반환


---

   읽기 전략

    Cache-Aside  Lazy Loading 

가장 범용적인 패턴이다. 애플리케이션이 직접 캐시를 확인하고, 없으면 DB를 조회해 캐시에 적재한다.

   java
@Service
@RequiredArgsConstructor
public class ProductService {

    private final ProductRepository productRepository;
    private final RedisTemplate<String, Product  redisTemplate;

    private static final String CACHE KEY PREFIX = "product:";
    private static final Duration TTL = Duration.ofMinutes 30 ;

    public Product getProduct Long id  {
        String key = CACHE KEY PREFIX + id;

        // 1. 캐시 조회
        Product cached = redisTemplate.opsForValue  .get key ;
        if  cached != null  {
            return cached; // 캐시 히트
        }

        // 2. DB 조회
        Product product = productRepository.findById id 
            .orElseThrow    -  new EntityNotFoundException "Product not found: " + id  ;

        // 3. 캐시 저장
        redisTemplate.opsForValue  .set key, product, TTL ;
        return product;
    }
}


  장점  
- 실제로 읽힌 데이터만 캐시에 올라간다 → 메모리 효율적
- DB 장애 시에도 캐시로 서비스 일부 유지 가능

  단점  
- 첫 요청은 항상 DB를 거친다  Cold Start 
- 캐시와 DB 간 데이터 불일치 가능성 존재

---

    Read-Through

캐시 레이어가 DB 조회까지 담당한다. 애플리케이션은 항상 캐시에만 요청한다.
Spring의  @Cacheable 이 이 방식을 추상화해 준다.

   java
@Service
public class ProductService {

    @Cacheable value = "product", key = " id", unless = " result == null" 
    public Product getProduct Long id  {
        return productRepository.findById id 
            .orElseThrow    -  new EntityNotFoundException "Product not found: " + id  ;
    }
}


   yaml
  application.yml
spring:
  cache:
    type: redis
  data:
    redis:
      host: localhost
      port: 6379


  장점  
- 코드가 단순해진다
- 캐시 로직이 서비스 레이어와 분리된다

  단점  
- 캐시 미스 시 응답 지연 발생
-  @Cacheable 의 동작 방식을 정확히 이해하지 못하면 예상치 못한 캐시 미스가 생길 수 있다

---

   쓰기 전략

    Write-Through

데이터 쓰기 시 캐시와 DB를 동시에 업데이트한다.

   java
@Service
@RequiredArgsConstructor
public class ProductService {

    private final ProductRepository productRepository;
    private final RedisTemplate<String, Product  redisTemplate;

    @Transactional
    public Product updateProduct Long id, UpdateProductRequest request  {
        Product product = productRepository.findById id 
            .orElseThrow    -  new EntityNotFoundException "Product not found: " + id  ;

        product.update request.getName  , request.getPrice   ;

        // DB 저장
        Product saved = productRepository.save product ;

        // 캐시도 즉시 업데이트
        String key = "product:" + id;
        redisTemplate.opsForValue  .set key, saved, Duration.ofMinutes 30  ;

        return saved;
    }
}


  장점  
- 캐시와 DB가 항상 동기화된다 → 데이터 정합성 높음

  단점  
- 자주 읽히지 않는 데이터도 캐시에 쌓인다
- 쓰기 요청마다 캐시 업데이트 비용이 추가된다

---

    Write-Behind  Write-Back 

쓰기를 캐시에만 먼저 반영하고, DB 동기화는 비동기로 나중에 처리한다.
쓰기 성능이 극도로 중요한 경우에 사용한다.


Client → Redis  즉시 응답 
              ↓  비동기, 일정 주기 
            DB 반영


  장점  
- 쓰기 TPS가 매우 높은 상황에서 유리

  단점  
- Redis 장애 시 DB에 반영되지 않은 데이터 유실 가능
- 구현 복잡도가 높다 → 일반적인 서비스에는 잘 사용하지 않는다

---

    Cache Invalidation  캐시 무효화 

데이터가 변경되면 해당 캐시를 삭제해, 다음 읽기 때 DB에서 최신 데이터를 가져오도록 한다.
 @CacheEvict 로 간단히 구현 가능하다.

   java
@CacheEvict value = "product", key = " id" 
@Transactional
public void deleteProduct Long id  {
    productRepository.deleteById id ;
}

// 특정 캐시 전체 비우기
@CacheEvict value = "product", allEntries = true 
public void clearAllProductCache   {
}


---

   주요 문제와 해결책

    Cache Stampede  캐시 스탬피드 

캐시 TTL이 만료되는 순간 수많은 요청이 동시에 DB로 몰리는 현상이다.


TTL 만료 → 100개 동시 요청 → 100개 모두 DB 조회 → DB 과부하


  해결책: Mutex Lock  분산 락   

   java
public Product getProductWithLock Long id  {
    String key = "product:" + id;
    String lockKey = "lock:product:" + id;

    Product cached = redisTemplate.opsForValue  .get key ;
    if  cached != null  return cached;

    // 락 획득 시도  10초 TTL 
    Boolean acquired = redisTemplate.opsForValue  
        .setIfAbsent lockKey, "locked", Duration.ofSeconds 10  ;

    if  Boolean.TRUE.equals acquired   {
        try {
            // DB 조회 후 캐시 저장
            Product product = productRepository.findById id 
                .orElseThrow    -  new EntityNotFoundException "Product not found: " + id  ;
            redisTemplate.opsForValue  .set key, product, Duration.ofMinutes 30  ;
            return product;
        } finally {
            redisTemplate.delete lockKey ;
        }
    } else {
        // 락을 못 얻은 경우 짧게 대기 후 재시도
        try { Thread.sleep 100 ; } catch  InterruptedException ignored  {}
        return getProductWithLock id ;
    }
}


---

    Cache Penetration  캐시 관통 

존재하지 않는 키로 반복 요청이 들어와 매번 DB를 거치게 되는 공격성 패턴이다.

  해결책: Null 캐싱  

   java
public Optional<Product  getProduct Long id  {
    String key = "product:" + id;
    String nullSentinel = "NULL";

    String raw = redisTemplate.opsForValue  .get key ;
    if  nullSentinel.equals raw   return Optional.empty  ; // null 캐시 히트

    if  raw != null  return Optional.of deserialize raw  ;

    Optional<Product  result = productRepository.findById id ;
    if  result.isPresent    {
        redisTemplate.opsForValue  .set key, serialize result.get   , Duration.ofMinutes 30  ;
    } else {
        // 존재하지 않는 데이터도 짧게 캐싱  5분 
        redisTemplate.opsForValue  .set key, nullSentinel, Duration.ofMinutes 5  ;
    }
    return result;
}


---

    Cache Avalanche  캐시 어벨랜치 

다수의 캐시가 동시에 만료되어 DB에 폭발적인 부하가 몰리는 현상이다.

  해결책: TTL 랜덤 분산  

   java
private Duration randomTTL long baseMinutes  {
    // 기본 TTL ± 20% 랜덤 편차
    long jitter =  long   baseMinutes   0.2    Math.random     2 - 1  ;
    return Duration.ofMinutes baseMinutes + jitter ;
}

redisTemplate.opsForValue  .set key, product, randomTTL 30  ;


---

   전략 선택 가이드

| 상황 | 권장 전략 |
|------|-----------|
| 읽기 비중이 높고 쓰기가 적다 | Cache-Aside + Write-Through |
| 쓰기가 매우 빈번하고 약간의 유실을 허용 | Write-Behind |
| 데이터 변경 후 즉시 일관성이 필요 | Cache Invalidation |
| 코드를 단순하게 유지하고 싶다 | Read-Through   @Cacheable   |
| 트래픽 급증 예상 | Cache Stampede 방어 추가 |

---

   캐시 TTL 설정 원칙


짧은 TTL  → 데이터 정합성↑, 캐시 히트율↓, DB 부하↑
긴 TTL    → 캐시 히트율↑, 데이터 불일치 위험↑


- 변경이 잦은 데이터: 5~10분
- 반정적 데이터  카테고리, 설정값 : 1~6시간
- 정적 데이터  약관, 공지 : 24시간 이상

---

캐싱 전략의 핵심은   데이터 정합성과 성능 사이의 트레이드오프  를 이해하고, 서비스의 특성에 맞는 전략을 선택하는 것이다.
"모든 걸 캐싱한다"가 아니라, "어떤 데이터를, 언제, 어떻게 무효화할 것인가"까지 설계해야 올바른 캐싱이다.

빈약한 도메인 모델  /posts/anemic-domain-model 이 안티패턴인 이유는 이미 잘 알려져 있다. 그 반대편에 있는 풍부한 도메인 모델 Rich Domain Model 은 단순히 "setter를 없애고 메서드를 추가하는 것"이 아니다. 도메인의 언어와 규칙을 코드로 표현하는 설계 전략이다.

   도메인 모델의 두 가지 핵심 구성 요소

풍부한 도메인 모델은   Entity  와   Value Object  로 이루어진다.

| 구분 | Entity | Value Object |
|------|--------|--------------|
| 식별 기준 | 고유 ID  동일성  | 속성 값  동등성  |
| 가변성 | 상태 변경 가능 | 불변 |
| 예시 | 주문, 고객, 상품 | 금액, 주소, 이메일, 날짜 범위 |

Entity는 시간이 지나도 같은 존재임을 ID로 식별한다. Value Object는 속성이 같으면 같은 것이다.

   Value Object — 불변 객체로 도메인 표현

 BigDecimal price 와  Money price 는 다르다.  BigDecimal 은 숫자일 뿐이지만,  Money 는 금액이라는 도메인 개념을 담는다.

    Money

   java
public final class Money {

    private final BigDecimal amount;
    private final Currency currency;

    private Money BigDecimal amount, Currency currency  {
        if  amount.compareTo BigDecimal.ZERO  < 0  {
            throw new IllegalArgumentException "금액은 0 이상이어야 합니다: " + amount ;
        }
        this.amount = amount.setScale 2, RoundingMode.HALF UP ;
        this.currency = currency;
    }

    public static Money of long amount, Currency currency  {
        return new Money BigDecimal.valueOf amount , currency ;
    }

    public static Money of BigDecimal amount, Currency currency  {
        return new Money amount, currency ;
    }

    public static Money krw long amount  {
        return Money.of amount, Currency.getInstance "KRW"  ;
    }

    // 불변 연산 — 새 객체를 반환한다
    public Money add Money other  {
        validateSameCurrency other ;
        return new Money this.amount.add other.amount , this.currency ;
    }

    public Money subtract Money other  {
        validateSameCurrency other ;
        BigDecimal result = this.amount.subtract other.amount ;
        if  result.compareTo BigDecimal.ZERO  < 0  {
            throw new InsufficientAmountException this, other ;
        }
        return new Money result, this.currency ;
    }

    public Money multiply int multiplier  {
        return new Money this.amount.multiply BigDecimal.valueOf multiplier  , this.currency ;
    }

    public Money applyDiscount DiscountRate rate  {
        return new Money this.amount.multiply BigDecimal.ONE.subtract rate.value    , this.currency ;
    }

    public boolean isGreaterThan Money other  {
        validateSameCurrency other ;
        return this.amount.compareTo other.amount    0;
    }

    private void validateSameCurrency Money other  {
        if  !this.currency.equals other.currency   {
            throw new CurrencyMismatchException this.currency, other.currency ;
        }
    }

    @Override
    public boolean equals Object o  {
        if  this == o  return true;
        if  ! o instanceof Money m   return false;
        return amount.compareTo m.amount  == 0 && currency.equals m.currency ;
    }

    @Override
    public int hashCode   {
        return Objects.hash amount.stripTrailingZeros  , currency ;
    }

    @Override
    public String toString   {
        return String.format "%s %s", currency.getCurrencyCode  , amount ;
    }
}


핵심은 세 가지다.

1.   불변   — 필드가  final 이고, 연산은 항상 새 객체를 반환한다
2.   자기검증   — 생성 시점에 유효성을 검증한다. 음수 금액은 존재할 수 없다
3.   동등성   —  equals / hashCode 를 값 기준으로 구현한다

Java 17 이상이라면  record 로 더 간결하게 표현할 수 있다.

   java
public record Email String value  {

    // compact constructor — record는 생성자에서 검증
    public Email {
        if  value == null || !value.matches "^ \\w. +@ \\w. +\\. a-z {2,}$"   {
            throw new InvalidEmailException value ;
        }
        value = value.toLowerCase  ;
    }

    public String domain   {
        return value.substring value.indexOf '@'  + 1 ;
    }
}


   java
// 사용
Email email = new Email "User@Example.com" ;
email.value     // "user@example.com" — 항상 소문자
email.domain    // "example.com"

// 동등성 비교 — record는 자동으로 값 기반 equals
new Email "user@example.com" .equals new Email "user@example.com"   // true


    날짜 범위 Value Object

   java
public record DateRange LocalDate start, LocalDate end  {

    public DateRange {
        Objects.requireNonNull start, "시작일은 필수입니다" ;
        Objects.requireNonNull end, "종료일은 필수입니다" ;
        if  start.isAfter end   {
            throw new InvalidDateRangeException start, end ;
        }
    }

    public boolean contains LocalDate date  {
        return !date.isBefore start  && !date.isAfter end ;
    }

    public boolean overlaps DateRange other  {
        return !this.end.isBefore other.start  && !other.end.isBefore this.start ;
    }

    public long days   {
        return ChronoUnit.DAYS.between start, end ;
    }

    public DateRange extend int days  {
        return new DateRange start, end.plusDays days  ;
    }
}


   java
DateRange summer = new DateRange 
    LocalDate.of 2026, 6, 1 ,
    LocalDate.of 2026, 8, 31 
 ;

summer.contains LocalDate.of 2026, 7, 15    // true
summer.days                                  // 91
summer.overlaps new DateRange ...            // 겹치면 true


날짜 범위라는 개념이 코드에 명확히 표현된다.  LocalDate start 와  LocalDate end 라는 두 필드가 분리되어 있을 때와 달리, 범위의 유효성과 관련 연산이 한 곳에 모인다.

   Aggregate — 일관성의 경계

Aggregate는 함께 변경되어야 하는 객체들의 묶음이다. 묶음에는 반드시 하나의   Aggregate Root  가 있고, 외부는 오직 Root를 통해서만 내부에 접근한다.


주문 Aggregate
┌─────────────────────────────────┐
│ Order  Aggregate Root           │
│   ├── OrderItem  Entity         │
│   │     ├── ProductId  VO       │
│   │     ├── Quantity  VO        │
│   │     └── Money  VO           │
│   ├── ShippingAddress  VO       │
│   ├── Money totalAmount  VO     │
│   └── OrderStatus  Enum/VO      │
└─────────────────────────────────┘


 OrderItem 을 직접 수정하는 것은 허용되지 않는다.  Order.addItem   ,  Order.removeItem   을 통해야 한다. 이것이 일관성 경계다.

    Aggregate 불변 규칙 Invariant 

   java
public class Order {

    private final OrderId id;
    private final CustomerId customerId;
    private OrderStatus status;
    private final List<OrderItem  items;
    private Money totalAmount;
    private ShippingAddress shippingAddress;

    // ── 생성 ──────────────────────────────────────────────

    public static Order place CustomerId customerId,
                               List<OrderItem  items,
                               ShippingAddress address  {
        // 불변 규칙: 주문은 아이템이 1개 이상이어야 한다
        if  items == null || items.isEmpty    {
            throw new EmptyOrderException  ;
        }
        // 불변 규칙: 아이템당 수량은 1~99개
        items.forEach OrderItem::validateQuantity ;

        Order order = new Order OrderId.generate  , customerId, address ;
        items.forEach order::addItemInternal ;
        return order;
    }

    // ── 행위 ──────────────────────────────────────────────

    public OrderItem addItem ProductId productId, Quantity quantity, Money unitPrice  {
        requireStatus OrderStatus.PENDING, "아이템 추가" ;

        // 불변 규칙: 같은 상품은 수량을 합산한다
        return items.stream  
            .filter item -  item.productId  .equals productId  
            .findFirst  
            .map existing -  {
                existing.increaseQuantity quantity ;
                recalculateTotal  ;
                return existing;
            } 
            .orElseGet    -  {
                OrderItem item = OrderItem.of productId, quantity, unitPrice ;
                items.add item ;
                recalculateTotal  ;
                return item;
            } ;
    }

    public void removeItem ProductId productId  {
        requireStatus OrderStatus.PENDING, "아이템 제거" ;

        boolean removed = items.removeIf item -  item.productId  .equals productId  ;
        if  !removed  throw new OrderItemNotFoundException productId ;

        // 불변 규칙: 아이템이 0개면 주문 자체를 유지할 수 없다
        if  items.isEmpty    throw new EmptyOrderException  ;

        recalculateTotal  ;
    }

    public void changeShippingAddress ShippingAddress newAddress  {
        requireStatus OrderStatus.PENDING, "배송지 변경" ;
        this.shippingAddress = Objects.requireNonNull newAddress ;
    }

    public void confirm   {
        requireStatus OrderStatus.PENDING, "주문 확정" ;
        this.status = OrderStatus.CONFIRMED;
    }

    public void cancel CancelReason reason  {
        if  status == OrderStatus.DELIVERED || status == OrderStatus.SHIPPED  {
            throw new OrderNotCancellableException id, status ;
        }
        if  status == OrderStatus.CANCELLED  {
            throw new OrderAlreadyCancelledException id ;
        }
        this.status = OrderStatus.CANCELLED;
    }

    // ── 내부 헬퍼 ──────────────────────────────────────────

    private void requireStatus OrderStatus required, String operation  {
        if  this.status != required  {
            throw new InvalidOrderStatusException id, operation, required, status ;
        }
    }

    private void recalculateTotal   {
        this.totalAmount = items.stream  
            .map OrderItem::subtotal 
            .reduce Money.krw 0 , Money::add ;
    }

    // 외부에서 items를 수정할 수 없도록
    public List<OrderItem  items   {
        return Collections.unmodifiableList items ;
    }
}


 recalculateTotal   이  addItem ,  removeItem  마다 호출된다. 총액이 아이템 합계와 다른 상태는 존재할 수 없다. 이것이 불변 규칙 Invariant 이다.

   도메인 이벤트

상태가 바뀌었을 때 다른 부분에 알려야 한다면 — 주문 확정 시 메일 발송, 재고 감소 — 어떻게 할까?

Service에서 직접 호출하면 도메인 로직과 부수 효과가 결합된다.

   java
// ❌ Service에 너무 많은 책임
public void confirmOrder OrderId orderId  {
    Order order = orderRepository.findById orderId .orElseThrow  ;
    order.confirm  ;
    orderRepository.save order ;

    // 도메인과 관계없는 부수 효과들
    emailService.sendConfirmationEmail order.customerId   ;
    inventoryService.decrease order.items   ;
    pointService.accumulate order.customerId  , order.totalAmount   ;
}


도메인 이벤트를 사용하면 도메인 객체는 "무슨 일이 일어났는가"만 기록하고, 그 결과로 무엇을 할지는 다른 곳에서 결정한다.

